import{_ as i,o as t,c as o,ag as a}from"./chunks/framework.BKDXG6j6.js";const u=JSON.parse('{"title":"Android Lifecycle","description":"","frontmatter":{},"headers":[],"relativePath":"android-core/lifecycle.md","filePath":"android-core/lifecycle.md","lastUpdated":null}'),c={name:"android-core/lifecycle.md"};function n(l,e,r,s,d,h){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="android-lifecycle" tabindex="-1">Android Lifecycle <a class="header-anchor" href="#android-lifecycle" aria-label="Permalink to &quot;Android Lifecycle&quot;">​</a></h1><p>Understanding lifecycles is crucial for avoiding memory leaks, crashes, and unpredictable behavior. Both <code>Activity</code> and <code>Fragment</code> have structured lifecycles.</p><h2 id="activity-lifecycle" tabindex="-1">Activity Lifecycle <a class="header-anchor" href="#activity-lifecycle" aria-label="Permalink to &quot;Activity Lifecycle&quot;">​</a></h2><ol><li><code>onCreate()</code>: Called when the activity is first created. Setup UI, initialize ViewModels, bind data.</li><li><code>onStart()</code>: Activity becomes visible to the user.</li><li><code>onResume()</code>: Activity comes to the foreground and becomes interactive.</li><li><code>onPause()</code>: Activity loses focus but might still be partially visible (e.g., dialer popup). Pause animations, camera previews.</li><li><code>onStop()</code>: Activity is no longer visible. Save state, release heavy resources.</li><li><code>onDestroy()</code>: Activity is destroyed. Release all references.</li></ol><h2 id="fragment-lifecycle" tabindex="-1">Fragment Lifecycle <a class="header-anchor" href="#fragment-lifecycle" aria-label="Permalink to &quot;Fragment Lifecycle&quot;">​</a></h2><p>Fragments have two distinct lifecycles: the Fragment instance lifecycle and the View lifecycle.</p><ol><li><code>onAttach()</code>: Attached to the host Activity.</li><li><code>onCreate()</code>: Fragment instance is created.</li><li><code>onCreateView()</code>: Inflate the UI view.</li><li><code>onViewCreated()</code>: Safe to start manipulating views (e.g., <code>findViewById</code>, ViewBinding).</li><li><code>onStart()</code> / <code>onResume()</code>: Mirrored from Activity.</li><li><code>onPause()</code> / <code>onStop()</code>: Mirrored from Activity.</li><li><code>onDestroyView()</code>: The view is destroyed. Null out ViewBindings here to prevent memory leaks!</li><li><code>onDestroy()</code> / <code>onDetach()</code>: The instance is destroyed and detached.</li></ol><h2 id="viewmodel-lifecycle" tabindex="-1">ViewModel Lifecycle <a class="header-anchor" href="#viewmodel-lifecycle" aria-label="Permalink to &quot;ViewModel Lifecycle&quot;">​</a></h2><p><code>ViewModel</code> survives configuration changes (like screen rotations).</p><ul><li>Created when the Activity/Fragment is first created.</li><li>Lives throughout rotations.</li><li><code>onCleared()</code> is called when the Activity is genuinely finished or the Fragment is permanently removed. This is where you should cancel Coroutines/RxJava streams.</li></ul><h2 id="saving-ui-state" tabindex="-1">Saving UI State <a class="header-anchor" href="#saving-ui-state" aria-label="Permalink to &quot;Saving UI State&quot;">​</a></h2><p>Apps might be killed by the system to free up resources.</p><ul><li><strong>ViewModel:</strong> Handles rotation but not system process death.</li><li><strong>SavedStateHandle:</strong> Integrated inside ViewModel to save and restore data across system process death.</li><li><strong>onSaveInstanceState()</strong>: Legacy way in Activities/Fragments to store lightweight UI data (e.g., scroll position, entered text) in a specific <code>Bundle</code>.</li></ul><h2 id="interview-questions" tabindex="-1">Interview Questions <a class="header-anchor" href="#interview-questions" aria-label="Permalink to &quot;Interview Questions&quot;">​</a></h2><p><strong>Q: Why do we null out ViewBinding in Fragment&#39;s <code>onDestroyView</code>?</strong><em>Answer:</em> A Fragment&#39;s instance might outlive its view (e.g., when it is in the back stack but not visible). If you keep a reference to the ViewBinding variable, the Views cannot be garbage collected, leading to a memory leak.</p><p><strong>Q: What is the lifecycle order when navigating from Activity A to Activity B?</strong><em>Answer:</em> A.onPause() -&gt; B.onCreate() -&gt; B.onStart() -&gt; B.onResume() -&gt; A.onStop(). Activity A only drops to <code>onStop()</code> <em>after</em> B has completed its layout and rendered its first frame.</p>',16)])])}const m=i(c,[["render",n]]);export{u as __pageData,m as default};
